import fs from 'fs';
import path from 'path';
import { fileURLToPath } from 'url';

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);
const REPO_ROOT = path.resolve(__dirname, '../..');

// Base URL for audio assets
const DEFAULT_BASE = process.env.RAILWAY_PUBLIC_DOMAIN 
  ? `https://${process.env.RAILWAY_PUBLIC_DOMAIN}` 
  : 'http://localhost:3000';

function cleanBaseUrl(value) {
  return String(value || '').trim().replace(/\/+$/, '');
}

let AUDIO_BASE_URL = cleanBaseUrl(process.env.AUDIO_ASSET_BASE || `${DEFAULT_BASE}/assets/audio`);

/**
 * Call this from routes.js with the actual request to set the correct base URL
 */
export function setAssetBaseUrl(req) {
  const protocol = req.headers['x-forwarded-proto'] || req.protocol || 'https';
  const host = req.headers['x-forwarded-host'] || req.get('host');
  const origin = `${protocol}://${host}`;
  AUDIO_BASE_URL = cleanBaseUrl(process.env.AUDIO_ASSET_BASE || `${origin}/assets/audio`);
}

