function envFlag(name) {
  return Boolean(String(process.env[name] || '').trim());
}

export function getAssetRuntimeDiagnostics() {
  return {
    mode: 'artist_agent',
    visualAssets: {
      source: 'AI Generated (NVIDIA FLUX)',
      count: 'Dynamic (10-20 per game)',
      library: 'DISABLED',
    },
    audioAssets: {
      source: 'Library',
      music: AUDIO_LIBRARY.music.length,
      sfx: AUDIO_LIBRARY.sfx.length,
      total: AUDIO_LIBRARY.music.length + AUDIO_LIBRARY.sfx.length,
    },
    models3D: {
      source: 'Procedural (Three.js)',
      primitives: MODEL_3D_LIBRARY.primitives,
    },
    env: {
      AUDIO_ASSET_BASE: envFlag('AUDIO_ASSET_BASE'),
      DISABLE_ARTIST_AGENT: envFlag('DISABLE_ARTIST_AGENT'),
      NVIDIA_API_KEY: envFlag('NVIDIA_API_KEY'),
    },
    deletedLibraries: {
      kenney: 'DELETED (107MB freed)',
      phaser: 'DELETED',
      embeddings: 'DELETED',
      catalogs: 'DELETED',
    },
  };
}

